int nPrintf(char *format, ...) {
  START_CRITICAL

  va_list ap;
  va_start(ap, format);
  int rc= vfprintf(stdout, format, ap);
  va_end(ap);
  if (rc>=0) {
    rc= fflush(stdout);
    if (rc<0)
      perror("fflush");
  }
  else
    perror("nPrintf");

  END_CRITICAL

  return rc;
}

int nFPrintf(FILE *file, char *format, ...) {
  START_CRITICAL

  va_list ap;
  va_start(ap, format);
  int rc= vfprintf(file, format, ap);
