int nOfrecer(nSubasta s, double oferta, int timeout) {
  START_CRITICAL

  nThread thisTh = nSelf();

  if (s->cerrada) {
    END_CRITICAL
    return FALSE;
  }

  // Create Oferta
  Oferta *o = (Oferta *)nMalloc(sizeof(Oferta));
  o->thread = thisTh;
  o->oferta = oferta;
  o->auction = s;
  thisTh->ptr = o;

  // Insert into sorted list (descending by oferta)
  // Ensure capacity
  if (s->num_ofertas == s->max_ofertas) {
    s->max_ofertas *= 2;
    s->ofertas = (Oferta **)nRealloc(s->ofertas, sizeof(Oferta *) * s->max_ofertas);
  }

  // Find insertion position (sorted desc by oferta)
  int pos = s->num_ofertas;
  for (int i = 0; i < s->num_ofertas; i++) {
    if (s->ofertas[i]->oferta < oferta) {
      pos = i;
      break;
    }
  }

  // Shift right
  for (int i = s->num_ofertas; i > pos; i--) {
    s->ofertas[i] = s->ofertas[i-1];
  }
  s->ofertas[pos] = o;
  s->num_ofertas++;

  // Check if list exceeds n
  if (s->num_ofertas > s->n) {
    // Remove the worst (last)
    s->num_ofertas--;
    Oferta *worst = s->ofertas[s->num_ofertas];
    if (worst->thread == thisTh) {
      // I lose immediately
      thisTh->ptr = NULL;
      nFree(worst);
      END_CRITICAL
      return FALSE;
    } else {
      // Cancel timer if applicable
      if (worst->thread->status == WAIT_SUBASTA_TIMEOUT) {
        nth_cancelThread(worst->thread);
      }
      // Wake up the loser
      setReady(worst->thread);
      // Don't free yet, the thread will free it (in the wake up logic)
    }
  }

  // Suspend waiting
  if (timeout < 0) {
    suspend(WAIT_SUBASTA);
  } else {
    suspend(WAIT_SUBASTA_TIMEOUT);
    nth_programTimer(timeout * 1000000LL, auctionWakeUp);
  }
  schedule();

  // Woken up. Check if I'm still in the list.
  int found = -1;
  for (int i = 0; i < s->num_ofertas; i++) {
    if (s->ofertas[i] == o) {
      found = i;
      break;
    }
  }

  int result;
  if (found >= 0) {
    // I'm in the list, I'm a winner
    result = TRUE;
  } else {
    // Not in list, I lost
    result = FALSE;
  }

  // Free the Oferta (winner or loser, doesn't matter)
  thisTh->ptr = NULL;
  nFree(o);

  END_CRITICAL
  return result;
}

