```c
#include <nthread-impl.h>
#include "subasta.h"

typedef struct Oferta {
  nThread thread;
  double oferta;
  struct subasta *auction;
} Oferta;

struct subasta {
  int n;
  int cerrada;
  Oferta **ofertas;
  int num_ofertas;
  int max_ofertas;
};

static void auctionWakeUp(nThread th) {
  Oferta *o = (Oferta *)th->ptr;
  if (o == NULL) return;
  nSubasta s = o->auction;

  // Find and remove o from s->ofertas
  for (int i = 0; i < s->num_ofertas; i++) {
    if (s->ofertas[i] == o) {
      for (int j = i; j < s->num_ofertas - 1; j++) {
        s->ofertas[j] = s->ofertas[j+1];
      }
      s->num_ofertas--;
      break;
    }
  }
}

nSubasta nNuevaSubasta(int n) {
  START_CRITICAL

  nSubasta s = (nSubasta)nMalloc(sizeof(struct subasta));
  s->n = n;
  s->cerrada = 0;
  s->max_ofertas = 4;
  s->ofertas = (Oferta **)nMalloc(sizeof(Oferta *) * s->max_ofertas);
  s->num_ofertas = 0;

  END_CRITICAL
  return s;
}

void nDestruirSubasta(nSubasta s) {
  START_CRITICAL

  for (int i = 0; i < s->num_ofertas; i++) {
    nFree(s->ofertas[i]);
  }
  nFree(s->ofertas);
  nFree(s);

  END_CRITICAL
}

int nOfrecer(nSubasta s, double oferta, int timeout) {
  START_CRITICAL

  nThread thisTh = nSelf();

  if (s->cerrada) {
    END_CRITICAL
    return FALSE;
  }

  // Create Oferta
  Oferta *o = (Oferta *)nMalloc(sizeof(Oferta));
  o->thread = thisTh;
  o->oferta = oferta;
  o->auction = s;
  thisTh->ptr = o;

  // Ensure capacity
  if (s->num_ofertas == s->max_ofertas) {
    s->max_ofertas *= 2;
    Oferta **new_arr = (Oferta **)nMalloc(sizeof(Oferta *) * s->max_ofertas);
    for (int i = 0; i < s->num_ofertas; i++) {
      new_arr[i] = s->ofertas[i];
    }
    nFree(s->ofertas);
    s->ofertas = new_arr;
  }

  // Find insertion position (sorted desc by oferta)
  int pos = s->num_ofertas;
  for (int i = 0; i < s->num_ofertas; i++) {
    if (s->ofertas[i]->oferta < oferta) {
      pos = i;
      break;
    }
  }

  // Shift right
  for (int i = s->num_ofertas; i > pos; i--) {
    s->ofertas[i] = s->ofertas[i-1];
  }
  s->ofertas[pos] = o;
  s->num_ofertas++;

  // Check if list exceeds n
  if (s->num_ofertas > s->n) {
    s->num_ofertas--;
    Oferta *worst = s->ofertas[s->num_ofertas];
    if (worst->thread == thisTh) {
      // I lose immediately
      thisTh->ptr = NULL;
      nFree(worst);
      END_CRITICAL
      return FALSE;
    } else {
      // Wake up the loser
      if (worst->thread->status == WAIT_SUBASTA_TIMEOUT) {
        nth_cancelThread(worst->thread);
      }
      setReady(worst->thread);
    }
  }

  // Suspend waiting
  if (timeout < 0) {
    suspend(WAIT_SUBASTA);
  } else {
    suspend(WAIT_SUBASTA_TIMEOUT);
    nth_programTimer(timeout * 1000000LL, auctionWakeUp);
  }
  schedule();

  // Woken up. Check cerrada.
  int result = s->cerrada ? TRUE : FALSE;

  // Free Oferta
  thisTh->ptr = NULL;
  nFree(o);

  END_CRITICAL
  return result;
}

double nAdjudicar(nSubasta s, int *punid) {
  START_CRITICAL

  s->cerrada = 1;

  double total = 0;
  for (int i = 0; i < s->num_ofertas; i++) {
    total += s->ofertas[i]->oferta;
  }

  if (punid != NULL) {
    int unsold = s->n - s->num_ofertas;
    *punid = unsold > 0 ? unsold : 0;
  }

  // Wake up all winners
  for (int i = 0; i < s->num_ofertas; i++) {
    Oferta *o = s->ofertas[i];
    if (o->thread->status == WAIT_SUBASTA_TIMEOUT) {
      nth_cancelThread(o->thread);
    }
    setReady(o->thread);
  }
  s->num_ofertas = 0;

  schedule();

  END_CRITICAL
  return total;
}
