#include <nthread-impl.h>
#include "subasta.h"

// =============================================================
// Estructura para representar una oferta dentro de la subasta
// =============================================================

typedef struct Oferta {
  nThread thread;          // thread que hizo la oferta
  double oferta;           // monto de la oferta
  struct subasta *auction; // puntero a la subasta a la que pertenece
} Oferta;

// =============================================================
// Estructura principal de la subasta
// =============================================================

struct subasta {
  int n;                   // numero de items a subastar
  int cerrada;             // 1 si la subasta fue cerrada (nAdjudicar)
  Oferta **ofertas;        // arreglo de punteros a Oferta, ordenado por oferta desc
  int num_ofertas;         // numero actual de ofertas en el arreglo
  int max_ofertas;         // capacidad del arreglo
};

// =============================================================
// Funcion auxiliar: wakeUpFun que se llama cuando se vence el
// timeout de un oferente.  Remueve al oferente de la lista de
// la subasta.
// =============================================================

static void auctionWakeUp(nThread th) {
  Oferta *o = (Oferta *)th->ptr;
  if (o == NULL) return;
  nSubasta s = o->auction;

  // Buscar y remover o de la lista
  int i, j;
  for (i = 0; i < s->num_ofertas; i++) {
    if (s->ofertas[i] == o) {
      // Compactar el arreglo
      for (j = i; j < s->num_ofertas - 1; j++) {
        s->ofertas[j] = s->ofertas[j+1];
      }
      s->num_ofertas--;
      break;
    }
  }
}

// =============================================================
// nNuevaSubasta: crea una nueva subasta para n items.
// Invocada por el dueno de la subasta.
// =============================================================

nSubasta nNuevaSubasta(int n) {
  START_CRITICAL

  nSubasta s = (nSubasta)nMalloc(sizeof(struct subasta));
  s->n = n;
  s->cerrada = 0;
  s->num_ofertas = 0;
  s->max_ofertas = (n > 4) ? n : 4;
